import React from 'react';
import './Design.css';
import { Link } from 'react-router-dom';
// import IMG from './IMG.jpg';



function Navbar() {
  return (
    <div>
      <ul className='header'>
        <li><Link to="/">Home</Link></li>
        <li>About</li>
        <li>Project</li>
        <li>Contact</li>
      </ul>

    </div>
  );
}

export default Navbar;
